sql:
SELECT * 
FROM key_events 
WHERE timestamp >= datetime('now', '-1 hour');

SELECT session_count AS total_sessions
FROM user_sessions
WHERE user_id = 1;

external_knowledge:
- 'certain user' refers to user_id = 123;
- 'workday hours' refers to the time between 9 AM and 5 PM (hours BETWEEN 9 AND 17);
- 'right at the start of each minute' signifies the time just after the minute changes, captured by milliseconds BETWEEN 0 AND 999.

sql:
SELECT AVG(key_hold_duration) AS average_duration
FROM key_events
WHERE user_id = 1;

SELECT user_id, key_code, COUNT(event_id) AS total_event_count 
FROM key_events 
GROUP BY user_id, key_code;

SELECT AVG(key_hold_duration) AS average_key_hold_duration
FROM key_events
WHERE application_id = 1;

SELECT MAX(event_frequency) AS max_event_frequency
FROM (
    SELECT event_id, COUNT(*) AS event_frequency
    FROM key_events
    GROUP BY event_id
);
